const d = $input.first().json;

// Dynamic recipient — escalates to higher authority each time
const to = d.escalateToEmail || 'escalations@example.com';

const escalationLevel = d.escalationLevel || 0;
const isMediaAlert = escalationLevel >= 3;
const daysOpen = d.daysOpen || 0;
const confirmations = d.confirmations || 0;

// Escalation level context
const levelInfo = {
  0: { authority: 'Ward Officer', deadline: '7 days', action: 'Site inspection and initial assessment' },
  1: { authority: 'Department Head', deadline: '7 days', action: 'Review ward officer inaction and assign repair team' },
  2: { authority: 'Commissioner Office', deadline: '7 days', action: 'Direct intervention — formal review of department failure' },
  3: { authority: 'Media & Public Alert', deadline: 'Immediate', action: 'Public accountability — media notification triggered' },
};

const current = levelInfo[escalationLevel] || levelInfo[0];
const previous = levelInfo[Math.max(0, escalationLevel - 1)] || levelInfo[0];

// Severity emoji + color context
const severityTag = {
  Critical: '🔴 CRITICAL',
  High: '🟠 HIGH',
  Medium: '🟡 MEDIUM',
  Low: '🟢 LOW',
}[d.severity] || '⚪ UNKNOWN';

// Urgency classification
const urgency = escalationLevel >= 3 ? '🚨 EMERGENCY'
  : escalationLevel >= 2 ? '⚠️ URGENT'
  : escalationLevel >= 1 ? '📢 ESCALATED'
  : '📋 ROUTINE';

const subject = `${urgency} ${d.issueType || 'Civic Issue'} — Escalation Level ${escalationLevel} — ${d.complaintId || d.issueId || 'N/A'}`;

let body = `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
${urgency} ESCALATION ALERT — JanaShakti Platform
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

COMPLAINT DETAILS
─────────────────
Complaint ID:    ${d.complaintId || d.issueId || 'N/A'}
Issue Type:      ${d.issueType || 'Unknown'}
Severity:        ${severityTag}
Location:        ${d.location || 'Not specified'}
City:            ${d.city || 'Not specified'}

STATUS
──────
Days Open:             ${daysOpen} days
Citizen Confirmations: ${confirmations}
Pressure Score:        ${confirmations * 10}/100

ESCALATION CHAIN
────────────────
Previous Level:  Level ${Math.max(0, escalationLevel - 1)} — ${d.previousLevel || previous.authority}
Current Level:   Level ${escalationLevel} — ${d.escalatedTo || current.authority}
Action Required: ${current.action}
Response Window: ${current.deadline}

ESCALATION HISTORY
──────────────────
Day 0:  ➡️  Ward Officer (initial assignment)${escalationLevel >= 1 ? `
Day 7:  ⬆️  Department Head (ward officer non-response)` : ''}${escalationLevel >= 2 ? `
Day 14: ⬆️  Commissioner Office (department failure)` : ''}${escalationLevel >= 3 ? `
Day 30: 🚨  Media & Public Alert (systemic non-action)` : ''}

⚠️ This issue has been UNRESOLVED for ${daysOpen} days despite ${confirmations} citizen confirmations.
`;

if (escalationLevel >= 2) {
  body += `
LEGAL NOTICE
────────────
Citizens have the right to file:
- RTI Application under Section 6(1) of RTI Act 2005
- Complaint with National Consumer Helpline (1915)
- Grievance on CPGRAMS (centralized public grievance portal)
${escalationLevel >= 3 ? '• High Court writ petition under Article 226 for systemic non-action' : ''}
An AI-generated RTI application is available on the JanaShakti platform.
`;
}

if (isMediaAlert) {
  body += `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🚨 MEDIA ALERT — PUBLIC ACCOUNTABILITY
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

This civic issue has been IGNORED for ${daysOpen}+ days and qualifies
for public media escalation under JanaShakti's accountability protocol.

The following actions have been triggered:
✅ Added to Wall of Shame (public visibility)
✅ Press release auto-generated for journalists
✅ Social media alert queued for @JanaShaktiApp
✅ Story marked as available in Journalist Dashboard
${confirmations >= 10 ? '✅ High community pressure — trending issue' : ''}

Responsible Department: ${d.departmentName || 'Municipal Corporation'}
Department was formally notified: Yes (via automated email)
Response received: None
`;
}

body += `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
Track this issue: https://janashakti.web.app/issue/${d.issueId || ''}

This is an automated escalation from JanaShakti (जनशक्ति) —
India's AI-powered civic accountability platform.

Powered by Google Gemini AI | Firebase | n8n Automation
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`;

return [{ json: { to, subject, body, isMediaAlert, escalationLevel, urgency, complaintId: d.complaintId || d.issueId } }];
